import{_ as e,o as a,c as i,e as l}from"./app-def54fd2.js";const t="/assets/image-20230905164333020-eca2b762.png",r="/assets/image-20230905164413270-369477ff.png",s={},h=l('<h1 id="mysql分表分库" tabindex="-1"><a class="header-anchor" href="#mysql分表分库" aria-hidden="true">#</a> MySQL分表分库</h1><h2 id="水平切分" tabindex="-1"><a class="header-anchor" href="#水平切分" aria-hidden="true">#</a> 水平切分</h2><p>水平切分又称为 Sharding，它是将同一个表中的记录拆分到多个结构相同的表中。</p><p>当一个表的数据不断增多时，Sharding 是必然的选择，它可以将数据分布到集群的不同节点上，从而缓存单个数据库的压力。</p><p><img src="'+t+'" alt="image-20230905164333020"></p><h2 id="垂直切分" tabindex="-1"><a class="header-anchor" href="#垂直切分" aria-hidden="true">#</a> 垂直切分</h2><p>垂直切分是将一张表按列切分成多个表，通常是按照列的关系密集程度进行切分，也可以利用垂直切分将经常被使用的列和不经常被使用的列切分到不同的表中。</p><p><img src="'+r+'" alt="image-20230905164413270"></p><h2 id="拆分策略" tabindex="-1"><a class="header-anchor" href="#拆分策略" aria-hidden="true">#</a> 拆分策略</h2><ul><li>哈希取模: hash(key) % NUM_DB</li><li>范围: 可以是 ID 范围也可以是时间范围</li><li>映射表: 使用单独的一个数据库来存储映射关系</li></ul><h2 id="问题及解决方案" tabindex="-1"><a class="header-anchor" href="#问题及解决方案" aria-hidden="true">#</a> 问题及解决方案</h2><ol><li>事务问题</li></ol><p>使用分布式事务来解决，比如 XA 接口。</p><ol start="2"><li><p>join 可以将原来的 JOIN 分解成多个单表查询，然后在用户程序中进行 JOIN。</p></li><li><p>ID 唯一性</p></li></ol><ul><li>使用全局唯一 ID: GUID</li><li>为每个分片指定一个 ID 范围</li><li>分布式 ID 生成器 (如 Twitter 的 Snowflake 算法)</li></ul><blockquote><p>参考材料：</p><p>https://pdai.tech/md/db/sql-mysql/sql-mysql-devide.html</p></blockquote>',16),d=[h];function n(c,o){return a(),i("div",null,d)}const _=e(s,[["render",n],["__file","MySQL分表分库.html.vue"]]);export{_ as default};
